# Let's prepare span_text values
aya_text = aya_sentence  # no final period
hadith_text = hadith_sentence  # no final period

# Gather quote blocks with classification we built earlier
quote_blocks = []
for (start_q, end_q, span, ayah_cue, hadith_cue, before_ctx, after_ctx) in pairs_with_classification:
    quote_blocks.append({
        'start_q': start_q,
        'end_q': end_q,
        'span_raw': span,
        'ayah_cue': ayah_cue,
        'hadith_cue': hadith_cue
    })

# For each match in matches_aya, check which block it belongs to
spans = []
for idx in matches_aya:
    # find block enclosing idx (idx should be >= start_q+1 and < end_q)
    block_found = None
    for b in quote_blocks:
        if b['start_q'] < idx < b['end_q']:
            block_found = b
            break
    if not block_found:
        # not inside any quote, then check local cues within ±64
        before = context_at(idx, s, 64)
        if any(c in before for c in aya_cues):
            # treat as ayah
            block_found = {'start_q': None, 'end_q': None, 'ayah_cue': True, 'hadith_cue': False}
    if block_found and block_found['ayah_cue']:
        start = idx
        end = start + len(aya_text)
        snippet = s[start:end]
        # ensure snippet equals aya_text
        if snippet != aya_text:
            # try trimming edges up to 2 characters inward
            ok = False
            for shift in range(1,3):
                if s[start+shift:end] == aya_text:
                    start = start+shift
                    end = start + len(aya_text)
                    ok = True
                    break
                if s[start:end-shift] == aya_text:
                    end = end-shift
                    ok = True
                    break
            if not ok:
                # last resort find the exact aya_text in the raw text near idx
                found = s.find(aya_text, max(0, idx-10), min(len(s), idx+10))
                if found != -1:
                    start = found
                    end = found + len(aya_text)
                else:
                    raise ValueError(f"Cannot locate aya_text near idx {idx}. snippet: {snippet[:50]}")
        # final assert
        assert s[start:end] == aya_text
        spans.append((start, end, aya_text, "Aya"))

for idx in matches_hadith:
    block_found = None
    for b in quote_blocks:
        if b['start_q'] < idx < b['end_q']:
            block_found = b
            break
    if not block_found:
        before = context_at(idx, s, 64)
        if any(c in before for c in hadith_cues):
            block_found = {'start_q': None, 'end_q': None, 'ayah_cue': False, 'hadith_cue': True}
    if block_found and block_found['hadith_cue']:
        start = idx
        end = start + len(hadith_text)
        snippet = s[start:end]
        if snippet != hadith_text:
            ok = False
            for shift in range(1,3):
                if s[start+shift:end] == hadith_text:
                    start = start+shift
                    end = start + len(hadith_text)
                    ok = True
                    break
                if s[start:end-shift] == hadith_text:
                    end = end-shift
                    ok = True
                    break
            if not ok:
                found = s.find(hadith_text, max(0, idx-10), min(len(s), idx+10))
                if found != -1:
                    start = found
                    end = found + len(hadith_text)
                else:
                    raise ValueError(f"Cannot locate hadith_text near idx {idx}. snippet: {snippet[:50]}")
        assert s[start:end] == hadith_text
        spans.append((start, end, hadith_text, "Hadeeth"))

spans_sorted = sorted(spans, key=lambda x: x[0])
spans_sorted, len(spans_sorted)

import json
output = {"citations":[]}
for start,end,span_text,ctype in spans_sorted:
    output["citations"].append({
        "span_start": start,
        "span_end": end,
        "span_text": span_text,
        "citation_type": ctype
    })
print(json.dumps(output, ensure_ascii=False, indent=2))
